const MAX_DATA_POINTS = 60; // Keep last 60 seconds of data
const UPDATE_INTERVAL = 1000; // 1 second

// Chart.js global defaults for dark theme
Chart.defaults.color = '#a0a0a0';
Chart.defaults.borderColor = 'rgba(255, 255, 255, 0.1)';
Chart.defaults.font.family = "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif";

// Initialize CPU Chart
const cpuCtx = document.getElementById('cpuChart').getContext('2d');
const cpuGradient = cpuCtx.createLinearGradient(0, 0, 0, 250);
cpuGradient.addColorStop(0, 'rgba(0, 212, 255, 0.5)');
cpuGradient.addColorStop(1, 'rgba(0, 212, 255, 0.05)');

const cpuChart = new Chart(cpuCtx, {
  type: 'line',
  data: {
    labels: [],
    datasets: [{
      label: 'CPU Usage (%)',
      data: [],
      borderColor: '#00d4ff',
      backgroundColor: cpuGradient,
      borderWidth: 2,
      fill: true,
      tension: 0.4,
      pointRadius: 0,
      pointHoverRadius: 4
    }]
  },
  options: {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        mode: 'index',
        intersect: false,
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        titleColor: '#00d4ff',
        bodyColor: '#ffffff',
        borderColor: 'rgba(255, 255, 255, 0.1)',
        borderWidth: 1
      }
    },
    scales: {
      x: {
        display: false
      },
      y: {
        beginAtZero: true,
        max: 100,
        grid: {
          color: 'rgba(255, 255, 255, 0.05)'
        },
        ticks: {
          callback: function(value) {
            return value + '%';
          }
        }
      }
    },
    interaction: {
      mode: 'nearest',
      axis: 'x',
      intersect: false
    }
  }
});

// Initialize Memory Chart
const memCtx = document.getElementById('memoryChart').getContext('2d');
const memGradient = memCtx.createLinearGradient(0, 0, 0, 250);
memGradient.addColorStop(0, 'rgba(123, 44, 191, 0.5)');
memGradient.addColorStop(1, 'rgba(123, 44, 191, 0.05)');

const memoryChart = new Chart(memCtx, {
  type: 'line',
  data: {
    labels: [],
    datasets: [{
      label: 'Memory Usage (%)',
      data: [],
      borderColor: '#7b2cbf',
      backgroundColor: memGradient,
      borderWidth: 2,
      fill: true,
      tension: 0.4,
      pointRadius: 0,
      pointHoverRadius: 4
    }]
  },
  options: {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        mode: 'index',
        intersect: false,
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        titleColor: '#7b2cbf',
        bodyColor: '#ffffff',
        borderColor: 'rgba(255, 255, 255, 0.1)',
        borderWidth: 1
      }
    },
    scales: {
      x: {
        display: false
      },
      y: {
        beginAtZero: true,
        max: 100,
        grid: {
          color: 'rgba(255, 255, 255, 0.05)'
        },
        ticks: {
          callback: function(value) {
            return value + '%';
          }
        }
      }
    },
    interaction: {
      mode: 'nearest',
      axis: 'x',
      intersect: false
    }
  }
});

// Update chart data helper
function updateChart(chart, label, value) {
  chart.data.labels.push(label);
  chart.data.datasets[0].data.push(value);

  if (chart.data.labels.length > MAX_DATA_POINTS) {
    chart.data.labels.shift();
    chart.data.datasets[0].data.shift();
  }

  chart.update('none'); // 'none' mode for performance
}

// Format uptime
function formatUptime(seconds) {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor((seconds % 86400) / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  const secs = Math.floor(seconds % 60);

  if (days > 0) return `${days}d ${hours}h ${minutes}m`;
  if (hours > 0) return `${hours}h ${minutes}m ${secs}s`;
  return `${minutes}m ${secs}s`;
}

// Connect to SSE endpoint
const eventSource = new EventSource('/events');

eventSource.onmessage = (event) => {
  const data = JSON.parse(event.data);
  const time = new Date(data.timestamp).toLocaleTimeString();

  // Update CPU
  updateChart(cpuChart, time, parseFloat(data.cpu));
  document.getElementById('cpuValue').textContent = `${data.cpu}%`;

  // Update Memory
  updateChart(memoryChart, time, parseFloat(data.memory.percent));
  document.getElementById('memoryValue').textContent = `${data.memory.percent}%`;

  // Update Memory Details
  document.getElementById('memTotal').textContent = `${data.memory.total} GB`;
  document.getElementById('memUsed').textContent = `${data.memory.used} GB`;
  document.getElementById('memFree').textContent = `${data.memory.free} GB`;
};

eventSource.onerror = (error) => {
  console.error('SSE Error:', error);
};

// Fetch static system info once on load
fetch('/api/system-info')
  .then(response => response.json())
  .then(data => {
    document.getElementById('platform').textContent = data.platform;
    document.getElementById('hostname').textContent = data.hostname;
  })
  .catch(err => console.error('Failed to load system info:', err));

// Update uptime every second
setInterval(() => {
  fetch('/api/uptime')
    .then(response => response.json())
    .then(data => {
      document.getElementById('uptime').textContent = formatUptime(data.uptime);
    })
    .catch(err => console.error('Failed to load uptime:', err));
}, 1000);
