const express = require('express');
const os = require('os');
const path = require('path');

const app = express();
const PORT = 3002;

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Store previous CPU times to calculate usage percentage
let previousCpuTimes = os.cpus();

function getCpuUsagePercent() {
  const currentCpuTimes = os.cpus();
  let totalUsage = 0;

  for (let i = 0; i < currentCpuTimes.length; i++) {
    const current = currentCpuTimes[i].times;
    const previous = previousCpuTimes[i] ? previousCpuTimes[i].times : current;

    const currentTotal = current.user + current.nice + current.sys + current.idle + current.irq;
    const previousTotal = previous.user + previous.nice + previous.sys + previous.idle + previous.irq;
    const totalDiff = currentTotal - previousTotal;
    const idleDiff = current.idle - previous.idle;

    const usagePercent = totalDiff === 0 ? 0 : 100 - (100 * idleDiff / totalDiff);
    totalUsage += usagePercent;
  }

  previousCpuTimes = currentCpuTimes;
  return (totalUsage / currentCpuTimes.length).toFixed(1);
}

function getMemoryStats() {
  const total = os.totalmem();
  const free = os.freemem();
  const used = total - free;
  return {
    total: (total / 1024 / 1024 / 1024).toFixed(2), // GB
    used: (used / 1024 / 1024 / 1024).toFixed(2),   // GB
    free: (free / 1024 / 1024 / 1024).toFixed(2),   // GB
    percent: ((used / total) * 100).toFixed(1)
  };
}

// API endpoint for static system info
app.get('/api/system-info', (req, res) => {
  res.json({
    platform: os.platform(),
    hostname: os.hostname()
  });
});

// API endpoint for uptime
app.get('/api/uptime', (req, res) => {
  res.json({
    uptime: os.uptime()
  });
});

// SSE endpoint for real-time system stats
app.get('/events', (req, res) => {
  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');

  const sendStats = () => {
    const stats = {
      cpu: getCpuUsagePercent(),
      memory: getMemoryStats(),
      timestamp: new Date().toISOString()
    };
    res.write(`data: ${JSON.stringify(stats)}\n\n`);
  };

  // Send initial stats immediately
  sendStats();

  // Send stats every 1000ms
  const intervalId = setInterval(sendStats, 1000);

  // Clean up on client disconnect
  req.on('close', () => {
    clearInterval(intervalId);
  });
});

app.listen(PORT, () => {
  console.log(`System Monitor running at http://localhost:${PORT}`);
});

